import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../components/Navbar';
import API from '../api/axios';

function HomePage() {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [theme, setTheme] = useState('dark');

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') || 'dark';
    setTheme(savedTheme);
    document.body.className = savedTheme === 'light' ? 'light-mode' : '';
    fetchPosts();
  }, []);

  const fetchPosts = async () => {
    try {
      const { data } = await API.get('/posts');
      setPosts(data);
    } catch (err) {
      console.error('Failed to fetch posts');
    } finally {
      setLoading(false);
    }
  };

  const toggleTheme = () => {
    const newTheme = theme === 'dark' ? 'light' : 'dark';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.body.className = newTheme === 'light' ? 'light-mode' : '';
  };

  if (loading) {
    return (
      <>
        <Navbar theme={theme} toggleTheme={toggleTheme} />
        <div className="container loading">Loading posts...</div>
      </>
    );
  }

  return (
    <>
      <Navbar theme={theme} toggleTheme={toggleTheme} />
      <main className="container">
        <section className="hero">
          <h2>Welcome to My Gaming World</h2>
          <p>Gaming Passion is a personal portfolio showcasing my journey from casual gaming to competitive play and esports enthusiasm.</p>
        </section>

        <section className="features">
          <h3>Latest Blog Posts</h3>
          {posts.length === 0 ? (
            <p>No posts yet. Be the first to write one!</p>
          ) : (
            <div className="posts-grid">
              {posts.map(post => (
                <div key={post._id} className="post-card">
                  {post.image && (
                    <img 
                      src={`http://localhost:5000/uploads/${post.image}`} 
                      alt={post.title}
                      className="post-card-image"
                    />
                  )}
                  <h3>{post.title}</h3>
                  <p className="post-excerpt">
                    {post.body.substring(0, 150)}...
                  </p>
                  <div className="post-meta">
                    By {post.author?.name} on {new Date(post.createdAt).toLocaleDateString()}
                  </div>
                  <Link to={`/posts/${post._id}`}>Read More →</Link>
                </div>
              ))}
            </div>
          )}
        </section>

        <section className="previews">
          <div className="preview-box">
            <h3>Explore My Journey</h3>
            <p>Discover how gaming became my passion and shaped my skills.</p>
          </div>
          <div className="preview-box">
            <h3>Join the Community</h3>
            <p>Register to get gaming updates, tips, and exclusive content.</p>
          </div>
        </section>

        <footer>
          <p>Contact: gaming@email.com</p>
          <p>© 2026 Gaming Passion</p>
        </footer>
      </main>
    </>
  );
}

export default HomePage;
